// Extract relevant fields from Calendly webhook payload
const payload = $input.first().json.payload;
const invitee = payload.invitee || {};
const event = payload.event || {};
const questions = payload.questions_and_answers || [];
const tracking = payload.tracking || {};

// ── Closer assignment from Calendly account ──
const CLOSER_MAP = {
  'c983b509-df1c-4661-aad5-8fb7bf40f8c4': 'Juan Martín',
  '908bf103-caf3-4476-92f6-4083ad615ab8': 'Agustín',
  'bf186137-c3be-4af2-9453-bec6af7ea3c2': 'Fede',
};

let closer = '';
const memberships = event.event_memberships || [];
for (const m of memberships) {
  const userUri = m.user || '';
  for (const [uuid, name] of Object.entries(CLOSER_MAP)) {
    if (userUri.includes(uuid)) { closer = name; break; }
  }
  if (closer) break;
}
if (!closer) {
  const eventTypeUri = (payload.event_type?.uri || event.uri || '');
  for (const [uuid, name] of Object.entries(CLOSER_MAP)) {
    if (eventTypeUri.includes(uuid)) { closer = name; break; }
  }
}

// ── UTM params ──
const utmSource = tracking.utm_source || '';
const utmMedium = tracking.utm_medium || '';
const utmCampaign = tracking.utm_campaign || '';
const setter = utmCampaign.includes('_') ? utmCampaign.split('_')[0] : utmCampaign;

// ── Event date ──
const startTime = event.start_time ? new Date(event.start_time) : new Date();
const fechaAgenda = startTime.toISOString().split('T')[0];
const today = new Date();
const mes = `${today.getFullYear()}-${today.getMonth() + 1}`;

// ── Parse ALL Calendly questions ──
let instagram = '';
let telefono = '';
let desdeDonde = '';
let modeloNegocio = '';
let objetivo = '';
let capacidadInversion = '';

for (const q of questions) {
  const ql = q.question.toLowerCase();
  const ans = q.answer || '';
  if (ql.includes('instagram') || ql.includes('ig') || ql.includes('usuario')) {
    instagram = ans;
  } else if (ql.includes('tel') || ql.includes('whatsapp') || ql.includes('número') || ql.includes('numero')) {
    telefono = ans;
  } else if (ql.includes('desde dónde') || ql.includes('desde donde') || ql.includes('agendaste')) {
    desdeDonde = ans;
  } else if (ql.includes('modelo') || ql.includes('describe')) {
    modeloNegocio = ans;
  } else if (ql.includes('objetivo')) {
    objetivo = ans;
  } else if (ql.includes('invertir') || ql.includes('inversión') || ql.includes('5.000')) {
    capacidadInversion = ans;
  }
}

// Build contextoSetter with all responses
const ctxParts = [];
if (desdeDonde) ctxParts.push('Fuente: ' + desdeDonde);
if (modeloNegocio) ctxParts.push('Modelo: ' + modeloNegocio);
if (objetivo) ctxParts.push('Objetivo: ' + objetivo);
if (capacidadInversion) ctxParts.push('Inversión: ' + capacidadInversion);
const contextoSetter = ctxParts.join(' | ');

// Auto-detect fuente from 'desde donde' if no UTM
let fuente = utmSource;
if (!fuente && desdeDonde) {
  const dd = desdeDonde.toLowerCase();
  if (dd.includes('instagram')) fuente = 'Instagram';
  else if (dd.includes('whatsapp')) fuente = 'WhatsApp';
  else if (dd.includes('youtube')) fuente = 'YouTube';
  else if (dd.includes('tiktok')) fuente = 'TikTok';
  else fuente = desdeDonde.substring(0, 30);
}

return [{
  json: {
    nombre: invitee.name || '',
    instagram: instagram,
    fechaLlamada: fechaAgenda,
    fechaAgenda: fechaAgenda,
    setter: setter,
    closer: closer,
    estado: '',
    sePresentó: '',
    calificado: '',
    programa: '',
    contextoSetter: contextoSetter,
    contextoCloser: '',
    cashDia1: '',
    cashTotal: '',
    ticketTotal: '',
    planPago: '',
    pago1: '',
    estadoPago1: '',
    pago2: '',
    estadoPago2: '',
    pago3: '',
    estadoPago3: '',
    saldoPendiente: '',
    fechaPago1: '',
    metodoPago: '',
    fuente: fuente,
    medioAgenda: utmMedium,
    email: invitee.email || '',
    telefono: telefono,
    mes: mes,
  }
}];
